var data = ($.steps.scrapePage.response && $.steps.scrapePage.response.data) ? $.steps.scrapePage.response.data : {};
var markdown = (data.markdown || '').slice(0, 5000);
var html = data.html || data.rawHtml || '';
var tables = html.match(/<table[\s\S]*?<\/table>/gi) || [];
var tableCount = tables.length;
var numbers = markdown.match(/\d+[,.]?\d*%?/g) || [];
var imgCount = (html.match(/<img /gi) || []).length;
var svgCount = (html.match(/<svg/gi) || []).length;
var canvasCount = (html.match(/<canvas/gi) || []).length;
return {
  markdown: markdown,
  tableCount: tableCount,
  tablePreview: tables.slice(0, 2).join('\n').slice(0, 2000),
  numberCount: numbers.length,
  imgCount: imgCount,
  chartElements: svgCount + canvasCount,
  keyNumbers: numbers.slice(0, 20).join(', ')
};

let raw = $.steps.aiAnalyze.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { text: raw }; }

var ai = $.steps.parseAI.output;
var ex = $.steps.extractData.output;
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':bar_chart: Data Analysis: ' + $.input.pageUrl.slice(0, 80), emoji: true } });
if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.summary } });
}
blocks.push({ type: 'divider' });
if (ai.trends && ai.trends.length > 0) {
  var trendsText = '*Trends*\n';
  ai.trends.forEach(function(t, i) { trendsText += ':chart_with_upwards_trend: ' + t + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: trendsText } });
}
if (ai.keyDataPoints && ai.keyDataPoints.length > 0) {
  blocks.push({ type: 'divider' });
  var dpText = '*Key Data Points*\n';
  ai.keyDataPoints.slice(0, 5).forEach(function(dp) {
    dpText += ':small_blue_diamond: *' + dp.metric + '*: ' + dp.value + ' (' + dp.significance + ')\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: dpText } });
}
if (ai.insights && ai.insights.length > 0) {
  blocks.push({ type: 'divider' });
  var insText = '*Insights*\n';
  ai.insights.forEach(function(ins, i) { insText += (i + 1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: insText } });
}
if (ai.anomalies && ai.anomalies.length > 0) {
  blocks.push({ type: 'divider' });
  var anText = '*:warning: Anomalies*\n';
  ai.anomalies.forEach(function(a) { anText += '- ' + a + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: anText } });
}
if (ai.recommendation) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Recommendation:* ' + ai.recommendation } });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':robot_face: Firecrawl + Claude AI | Tables: ' + ex.tableCount + ' | Charts: ' + ex.chartElements + ' | Data points: ' + ex.numberCount }] });
var fallback = ai.summary ? ai.summary.slice(0, 500) : (ai.text || '').slice(0, 500);
return { blocks, fallback };
